    $vi${"category":"business","categoryLabel":"Business & Investment","episodeNo":"01","rev":"01","seriesNav":[{"no":"01","label":"Hệ thống Visa & Lộ trình Cá thể","active":true},{"no":"02","label":"Lựa chọn Ngành & Nhượng quyền"},{"no":"03","label":"Quy trình Di trú 5 Giai đoạn"},{"no":"04","label":"Thường trú & Định cư"}],"title":"Cách bắt đầu kinh doanh tại Hàn Quốc cho người nước ngoài — Hướng dẫn toàn diện về visa D-9-4, D-9-5 cho hộ kinh doanh cá thể (2026)","ogTitle":"Hướng dẫn visa D-9-4 & D-9-5: Định cư kinh doanh cá thể tại Hàn Quốc (2026)","url":"cach-bat-dau-kinh-doanh-tai-han-quoc-cho-nguoi-nuoc-ngoai-2026","lang":"vi","translation_group":"biz-immigration-ep1","translations":{"en":"start-a-business-in-korea-as-a-foreigner-2026","zh":"外国人在韩国创业-D-9-4-D-9-5签证完全指南-2026","vi":"cach-bat-dau-kinh-doanh-tai-han-quoc-cho-nguoi-nuoc-ngoai-2026"},"disclaimer":"Đây là phần đầu tiên của loạt bài cho người nước ngoài đang xem xét Định cư Kinh doanh tại Hàn Quốc. Logic lựa chọn ngành và nhượng quyền chi tiết được trình bày ở Tập 2, toàn bộ quy trình di trú và khởi nghiệp ở Tập 3, và cuộc sống sau khi định cư ở Tập 4.","metaDescription":"Hướng dẫn toàn diện 2026 về Định cư Kinh doanh tại Hàn Quốc cho hộ kinh doanh cá thể nước ngoài. Vì sao D-9-4 và D-9-5 — không phải D-8 — phù hợp với chủ doanh nghiệp nhỏ, cũng như cách thức đầu tư, chuyển đổi tư cách lưu trú, gia hạn lưu trú và visa thân nhân hoạt động trong thực tế.","series":"Episode 1 · Chuỗi Định cư Kinh doanh","publishedAt":"2026.04.10","updatedAt":"2026.05.06","readingMin":13,"sections":[{"id":"s1","heading":"Visa kinh doanh Hàn Quốc không chỉ có D-8","blocks":[{"type":"p","text":"Đối với người nước ngoài đang tìm cách kinh doanh tại Hàn Quốc, loại visa đầu tiên họ thường gặp là <b>visa D-8</b>. Các công ty tư vấn di trú nước ngoài, tài liệu tiếng Anh của chính phủ Hàn Quốc, và hầu hết bài báo đều giới thiệu D-8 là 'visa kinh doanh' của Hàn Quốc. Kết quả là nhiều người nộp đơn cho rằng D-8 là bắt buộc để khởi nghiệp bất kỳ loại hình nào tại Hàn Quốc."},{"type":"p","text":"Trên thực tế, D-8 được thiết kế cho <b>người nước ngoài thành lập pháp nhân hoặc đầu tư vào pháp nhân hiện có</b>. Các phân loại con của nó làm rõ điều này: D-8-1 cho chuyên gia thiết yếu (như giám đốc) của pháp nhân được đầu tư nước ngoài, D-8-2 cho người sáng lập công ty mạo hiểm, D-8-3 cho đối tác liên doanh với công dân Hàn Quốc, và D-8-4 cho người sáng lập startup dựa trên công nghệ. Tất cả đều giả định một <b>pháp nhân hoặc doanh nghiệp được hỗ trợ bởi đầu tư</b>. Người nộp đơn thành lập hoặc gia nhập một thực thể pháp nhân và lưu trú tại Hàn Quốc với tư cách đại diện hoặc thành viên ban điều hành."},{"type":"p","text":"Nhưng phần lớn những người đang xem xét Định cư Kinh doanh không có kế hoạch thành lập doanh nghiệp cấp pháp nhân hay startup công nghệ. Họ đang lên kế hoạch <b>kinh doanh nhỏ theo hình thức hộ kinh doanh cá thể</b>: cửa hàng tiện lợi, quán cà phê, cửa hàng bán lẻ không người, nhà hàng Hàn Quốc, salon tóc, tiệm giặt ủi tự phục vụ. Đối với loại di trú này, D-8 không phải là visa phù hợp — một loại khác sẽ áp dụng."}]},{"id":"s2","heading":"D-9-4 và D-9-5 — visa được thiết kế cho hộ kinh doanh cá thể nước ngoài","blocks":[{"type":"p","text":"Hàn Quốc duy trì một kênh visa riêng cho <b>hộ kinh doanh cá thể nước ngoài</b>: <b>D-9-4</b> và <b>D-9-5</b>."},{"type":"table","title":"Tổng quan D-9-4 · D-9-5","headers":["Visa","Đối tượng đủ điều kiện","Mức đầu tư tối thiểu"],"rows":[["D-9-4","Người nước ngoài chuyển tiền từ nước ngoài, đăng ký kinh doanh dưới tên mình với tư cách hộ cá thể, và tự điều hành doanh nghiệp","Từ 300 triệu KRW"],["D-9-5","Cựu du học sinh có bằng thạc sĩ trở lên tại Hàn Quốc — hoặc bằng cử nhân cộng 30 điểm OASIS trở lên (xét tuyển dựa trên điểm cho khởi nghiệp) — khởi nghiệp tại Hàn Quốc","Từ 100 triệu KRW"]],"note":"Cả hai visa đều mở cho mọi quốc tịch và hầu như không giới hạn ngành nghề."},{"type":"p","text":"<b>D-9-4</b> không yêu cầu thành lập pháp nhân. Người nộp đơn đăng ký kinh doanh dưới tên mình với tư cách hộ kinh doanh cá thể. Quốc tịch không bị giới hạn, và phạm vi ngành nghề được phép là rất rộng."},{"type":"p","text":"<b>D-9-5</b> là visa kênh đặc biệt cho <b>cựu du học sinh đã tốt nghiệp tại đại học Hàn Quốc</b>. Visa này cho phép những người đã hoàn thành học tập tại Hàn Quốc tiếp tục ở lại với tư cách doanh nhân thay vì trở về nước, với ngưỡng đầu tư thấp hơn đáng kể."},{"type":"callout","text":"Mặc dù cả hai visa trực tiếp tương ứng với di trú kinh doanh nhỏ theo hộ cá thể, <b>các loại visa này gần như hoàn toàn vắng mặt trong các tài liệu của công ty tư vấn di trú nước ngoài về Hàn Quốc</b>. Vì D-8 đã trở thành điểm tham chiếu mặc định cho 'visa kinh doanh Hàn Quốc', nhiều người nộp đơn hoặc từ bỏ hoàn toàn ý định Định cư Kinh doanh tại Hàn Quốc, hoặc theo đuổi con đường D-8 không phù hợp — đơn giản vì không biết đến lộ trình hộ cá thể."},{"type":"p","text":"<b>Lawyeon Trung tâm Hỗ trợ Xuất nhập cảnh & Di trú chuyên về D-9-4 và D-9-5 — kênh Định cư Kinh doanh hộ cá thể cho người nước ngoài.</b> Chúng tôi tích hợp các khía cạnh pháp lý, hợp đồng và vận hành của di trú hộ kinh doanh cá thể Hàn Quốc thành một dự án duy nhất, và đây là lĩnh vực hành nghề chuyên biệt của chúng tôi."}]},{"id":"s3","heading":"Đầu tư được đánh giá không phải bởi 'bao nhiêu' mà là 'đến bằng cách nào'","blocks":[{"type":"p","text":"Ngưỡng đầu tư tối thiểu rất đơn giản: <b>từ 300 triệu KRW cho D-9-4</b> và <b>từ 100 triệu KRW cho D-9-5</b>. Bản thân các con số rất rõ ràng. Tuy nhiên, điều thực sự quan trọng trong xét duyệt không phải là <b>quy mô</b> số tiền mà là <b>cách số tiền đó đã đến Hàn Quốc</b>."},{"type":"numbered","label":"YÊU CẦU","items":[{"n":1,"title":"Chuyển tiền dưới tên người nộp đơn","text":"Tiền đầu tư phải được chuyển từ tài khoản nước ngoài của chính người nộp đơn tới tài khoản Hàn Quốc đứng tên người nộp đơn. Tiền chuyển từ tài khoản bên thứ ba, tiền vay tại Hàn Quốc, tiền đem đến qua tiền điện tử, và tiền đi qua các ứng dụng chuyển tiền hoặc thanh toán đều không được công nhận là vốn đầu tư. Ngay cả khi thành viên gia đình chuyển tiền thay, người nộp đơn vẫn phải chứng minh riêng rằng số tiền đó thực chất thuộc về họ."},{"n":2,"title":"Mục đích chuyển tiền rõ ràng","text":"Khi chuyển tiền đến Hàn Quốc, mục đích khai báo với ngân hàng phải nêu rõ <b>'đầu tư'</b>. Nếu số tiền ban đầu được khai báo là 'chi phí sinh hoạt', 'chi phí du lịch' hoặc 'học phí' rồi sau đó chuyển sang sử dụng kinh doanh, việc công nhận là vốn đầu tư trở nên khó khăn."},{"n":3,"title":"Tính hợp pháp của nguồn tiền","text":"Người nộp đơn phải có khả năng chứng minh số tiền đã được tích lũy như thế nào tại nước nhà. Thu nhập từ việc làm cần giấy chứng nhận việc làm và bảng lương; thu nhập kinh doanh cần hồ sơ vận hành và khai thuế; thừa kế hoặc tặng cho cần các giấy chứng nhận tương ứng; bán tài sản cần hợp đồng bán và hồ sơ về tiền thu được. <b>Sự rõ ràng về nguồn gốc có trọng số lớn hơn quy mô tuyệt đối</b> trong xét duyệt."}]}]},{"id":"s4","heading":"Một phần trong 100 triệu KRW có thể là vốn nội địa — điều khoản đặc biệt của D-9-5","blocks":[{"type":"p","text":"Đối với D-9-5, <b>tối đa 50 triệu KRW trong khoản đầu tư 100 triệu KRW có thể là vốn huy động trong nước Hàn Quốc</b>. 50 triệu KRW còn lại vẫn phải là vốn nước ngoài chuyển từ nước ngoài về."},{"type":"p","text":"Tiền thường đủ điều kiện được coi là huy động trong nước bao gồm tiết kiệm tích lũy trong thời gian học tại Hàn Quốc — làm thêm, trợ giảng, học bổng, hoặc tiền gia đình chuyển mà người nộp đơn giữ trong tài khoản Hàn Quốc khi đang lưu trú với tư cách D-2 (Du học) hoặc D-10 (Tìm việc). Ngay cả trong trường hợp này, người nộp đơn vẫn phải chứng minh tiền được tích lũy hợp pháp."},{"type":"callout","text":"Điều khoản này được thiết kế để <b>những người đã hoàn thành học tại Hàn Quốc có thể bắt đầu kinh doanh riêng mà không phụ thuộc vào tiền chuyển từ quê nhà</b>. Đối với người nộp đơn không thể chuyển toàn bộ số tiền từ nước ngoài, hoặc đã tích lũy tiết kiệm trong thời gian học tại Hàn Quốc, D-9-5 thực sự dễ tiếp cận hơn D-9-4."}]},{"id":"s-cta-mid","type":"midCta","blocks":[]},{"id":"s5","heading":"Tiền phải được chi vào đâu để được công nhận là 'đầu tư'","blocks":[{"type":"p","text":"Việc chỉ giữ tiền chuyển trong tài khoản cá nhân tại Hàn Quốc không đủ để được công nhận là vốn đầu tư. Phải có <b>bằng chứng tài liệu cho thấy số tiền thực sự được triển khai vào doanh nghiệp</b>."},{"type":"table","title":"Cách sử dụng vốn đầu tư được công nhận và không được công nhận","headers":["Triển khai được công nhận","Triển khai không được công nhận"],"rows":[["Phí nhượng quyền · tiền đặt cọc thuê","Chi phí sinh hoạt cá nhân (nhà ở, ăn uống, viễn thông)"],["Trang trí nội thất · trang thiết bị","Mua tài sản không liên quan đến doanh nghiệp"],["Mua hàng tồn kho ban đầu","Cho người nộp đơn hoặc gia đình vay"],["Phí tư vấn · vốn lưu động","Thanh toán cho các đơn vị không có thực thể kinh doanh rõ ràng"]],"note":"Mỗi mục cần hồ sơ chuyển tiền, hợp đồng, hóa đơn thuế và biên lai; nguồn tiền phải truy ngược được về tài khoản chuyển tiền của chính người nộp đơn."},{"type":"p","text":"Đây chính là lý do thiết kế dự án của chúng tôi bắt đầu bằng kế hoạch phân bổ ngân sách. Thay vì chuyển 300 triệu hoặc 100 triệu KRW trước rồi mới quyết định chi tiêu ở đâu, <b>kế hoạch triển khai nên được thiết kế trước khi di trú, và tiền nên được di chuyển theo kế hoạch đó để vốn đầu tư được công nhận đầy đủ tại thời điểm xét duyệt visa</b>."}]},{"id":"s6","heading":"Đối với người đã lưu trú tại Hàn Quốc — tiếp tục với visa kinh doanh qua chuyển đổi tư cách","blocks":[{"type":"p","text":"Tất cả những điều trên giả định di trú từ nước ngoài. Nhưng cũng có <b>người nước ngoài đã lưu trú tại Hàn Quốc</b>. Các trường hợp điển hình bao gồm những người mang F-3 (Thân nhân đi cùng) với tư cách thành viên gia đình của vợ/chồng người Hàn, những người mang E-7 (Hoạt động đặc biệt) làm việc tại công ty Hàn Quốc, và những người mang D-2 (Du học) hoặc D-10 (Tìm việc)."},{"type":"p","text":"Những người đã ở Hàn Quốc có thể tiếp tục với visa kinh doanh thông qua <b>chuyển đổi tư cách lưu trú</b>, mà không cần phải trở về nước nhà. Thay vì xin visa D-9 mới qua cơ quan đại diện ngoại giao Hàn Quốc ở nước ngoài, đơn được nộp trực tiếp tại Cục quản lý xuất nhập cảnh trong Hàn Quốc. Gánh nặng tài liệu từ quê nhà được giảm đáng kể, và toàn bộ thủ tục có thể hoàn thành tại Hàn Quốc mà không gián đoạn lưu trú."},{"type":"p","text":"Đối với cựu du học sinh đáp ứng yêu cầu D-9-5, đây là lộ trình mặc định. Vì cả bằng cấp Hàn Quốc và hồ sơ lưu trú đều có thể xác minh trong nước, chuyển đổi tư cách trong nước là lộ trình tự nhiên. Những người hiện đang ở Hàn Quốc với tư cách việc làm hoặc thân nhân đi cùng muốn chuyển sang kinh doanh cũng có thể theo đuổi chuyển đổi tư cách trong nước, với điều kiện đáp ứng các yêu cầu."}]},{"id":"s7","heading":"Thời hạn lưu trú và xét duyệt gia hạn","blocks":[{"type":"p","text":"Đối với cả D-9-4 và D-9-5, <b>thời hạn lưu trú ban đầu thường là 1 năm</b>. Tiếp tục lưu trú tại Hàn Quốc sau đó yêu cầu gia hạn thời hạn lưu trú."},{"type":"p","text":"Điều được đánh giá ở xét duyệt gia hạn là <b>liệu doanh nghiệp có thực sự đang hoạt động hay không</b>. Cụ thể, doanh thu, lịch sử khai thuế, duy trì cơ sở kinh doanh, tình trạng tuyển dụng, và tính liên tục của hợp đồng thuê thương mại đều được kiểm tra. Người nộp đơn chỉ đáp ứng ngưỡng đầu tư hình thức tại thời điểm cấp visa nhưng không có hoạt động kinh doanh thực tế sẽ thấy việc gia hạn khó khăn."},{"type":"callout","text":"Hàm ý rất rõ. Trong Định cư Kinh doanh, có được visa không phải là vạch đích — <b>duy trì hoạt động kinh doanh tích cực là điều kiện để duy trì lưu trú</b>. Đây là lý do trung tâm chúng tôi cung cấp hỗ trợ pháp lý sau định cư như một dịch vụ riêng biệt liên tục, ngoài công việc di trú và khởi nghiệp ban đầu. Tập 4 đề cập chi tiết viễn cảnh dài hạn này."}]},{"id":"s8","heading":"Mời thân nhân đi cùng — đưa vợ/chồng và con đến với tư cách F-3","blocks":[{"type":"p","text":"Người sở hữu D-9-4 hoặc D-9-5 có thể <b>mời vợ/chồng và con vị thành niên đến Hàn Quốc</b>. Tư cách lưu trú cấp cho thành viên gia đình là <b>F-3 (Thân nhân đi cùng)</b>."},{"type":"p","text":"Thủ tục mời như sau: người nộp đơn chính trước tiên xin <b>Giấy xác nhận cấp visa (CCVI, 사증발급인정서)</b> từ Cục quản lý xuất nhập cảnh tại Hàn Quốc; thành viên gia đình ở nước ngoài sau đó dùng giấy xác nhận này để nộp đơn xin visa F-3 tại cơ quan đại diện ngoại giao Hàn Quốc có thẩm quyền. Thời hạn lưu trú F-3 gắn với thời hạn lưu trú của người sở hữu chính (người sở hữu D-9). Khi người sở hữu chính được gia hạn, F-3 của gia đình có thể được gia hạn cùng; ngược lại, nếu lưu trú của người sở hữu chính kết thúc, F-3 của gia đình cũng kết thúc."},{"type":"p","text":"Một điểm cần lưu ý về F-3: <b>việc làm bị hạn chế theo nguyên tắc chung</b>. Nếu vợ/chồng muốn tìm việc làm riêng tại Hàn Quốc, cần xem xét chuyển từ F-3 sang tư cách cho phép làm việc một cách riêng biệt. Đối với con cái trong tuổi đi học, có thể nhập học các trường công lập hoặc tư thục Hàn Quốc, và tuyển sinh tuyển sinh đặc biệt cho học sinh nước ngoài được cung cấp cho tuyển sinh đại học."},{"type":"p","text":"Mời cha mẹ không khả thi chỉ với tư cách của người sở hữu D-9; cần được xem xét riêng qua tư cách khác (ví dụ: F-1 Thăm viếng/Cùng cư trú). Phạm vi thành viên gia đình được mời và thiết kế tư cách cho từng người là điều chúng tôi cùng xem xét trong giai đoạn tư vấn sơ bộ."}]},{"id":"closing","heading":"Nội dung các tập tiếp theo","blocks":[{"type":"p","text":"Phần này hoàn thành tổng quan về hệ thống visa Định cư Kinh doanh của Hàn Quốc — vì sao D-9-4 và D-9-5, không phải D-8, là loại visa phù hợp cho doanh nhân hộ kinh doanh cá thể nước ngoài, và hệ thống hoạt động trong thực tế ra sao: công nhận đầu tư, chuyển đổi tư cách cho người đã ở Hàn Quốc, gia hạn thời hạn lưu trú, và mời thân nhân đi cùng."},{"type":"p","text":"Ba tập tiếp theo chuyển từ visa sang dự án thực tế."},{"type":"numbered","label":"TẬP","items":[{"n":2,"title":"Tập 2 — Lựa chọn ngành & vì sao nhượng quyền phù hợp","text":"Loại hình kinh doanh nào phù hợp với người nộp đơn Định cư Kinh doanh, kinh nghiệm lưu trú Hàn Quốc thay đổi lựa chọn ra sao, và vì sao nhượng quyền Hàn Quốc — được hỗ trợ bởi Tài liệu công khai thông tin nhượng quyền do luật quy định — là lộ trình có thể dự đoán nhất cho người mới đến."},{"n":3,"title":"Tập 3 — Quy trình di trú 5 giai đoạn","text":"Nội dung của tư vấn sơ bộ, tư vấn chính thức, khởi động, định cư, và hỗ trợ tiếp nối — dự án thực tế diễn ra như thế nào từ quê nhà đến ngày khai trương tại Hàn Quốc."},{"n":4,"title":"Tập 4 — Thường trú & định cư","text":"Lưu trú dài hạn, lộ trình từ F-2-99 đến F-5, định cư gia đình, bất động sản, bảo vệ thuê thương mại, chăm sóc sức khỏe, và cấu trúc của hỗ trợ pháp lý liên tục — viễn cảnh dài hạn bắt đầu sau khi visa được cấp."}]},{"type":"p","text":"Lawyeon Trung tâm Hỗ trợ Xuất nhập cảnh & Di trú quy tụ các luật sư giàu kinh nghiệm từ Văn phòng Luật Lawyeon, điều phối viên-phiên dịch, và chuyên gia di trú khởi nghiệp để hỗ trợ Định cư Kinh doanh hộ cá thể của người nước ngoài qua D-9-4 và D-9-5. Tư vấn ban đầu miễn phí, và người nộp đơn có thể gửi yêu cầu trực tiếp từ quê nhà qua luồng tư vấn của chúng tôi."}]}],"related":[{"tag":"EP 2","title":"Người nước ngoài nên mở loại nhượng quyền nào tại Hàn Quốc? Ngành, thương hiệu & Tài liệu công khai (2026)","url":"kinh-doanh-nhuong-quyen-tai-han-quoc-cho-nguoi-nuoc-ngoai-2026"},{"tag":"EP 3","title":"Cách mở cửa hàng tại Hàn Quốc cho người nước ngoài — Quy trình từng bước 2026 từ tư vấn sơ bộ đến ngày khai trương","url":"quy-trinh-mo-cua-hang-tai-han-quoc-cho-nguoi-nuoc-ngoai-2026"},{"tag":"EP 4","title":"Thường trú tại Hàn Quốc cho chủ doanh nghiệp nước ngoài — F-2-99, gia đình, bất động sản & định cư (2026)","url":"thuong-tru-tai-han-quoc-cho-chu-doanh-nghiep-nuoc-ngoai-2026"}]}$vi$::jsonb,
    NOW(),
