    $vi$[]$vi$::jsonb,
    $vi${"category":"business","categoryLabel":"Business & Investment","episodeNo":"04","rev":"01","seriesNav":[{"no":"01","label":"Hệ thống Visa & Lộ trình Cá thể"},{"no":"02","label":"Lựa chọn Ngành & Nhượng quyền"},{"no":"03","label":"Quy trình Di trú 5 Giai đoạn"},{"no":"04","label":"Thường trú & Định cư","active":true}],"title":"Thường trú tại Hàn Quốc cho chủ doanh nghiệp nước ngoài — F-2-99, gia đình, bất động sản & định cư (2026)","ogTitle":"Từ D-9 đến F-2-99: Thường trú cho chủ doanh nghiệp nước ngoài tại Hàn Quốc (2026)","url":"thuong-tru-tai-han-quoc-cho-chu-doanh-nghiep-nuoc-ngoai-2026","lang":"vi","translation_group":"biz-immigration-ep4","translations":{"en":"permanent-residency-korea-foreign-business-owner-2026","zh":"外国企业主韩国永久居留-F-2-99到F-5指南-2026","vi":"thuong-tru-tai-han-quoc-cho-chu-doanh-nghiep-nuoc-ngoai-2026"},"disclaimer":"Tập 4, cũng là tập cuối, trong loạt Định cư Kinh doanh. Tập 1 đến 3 đã trình bày hệ thống visa D-9-4 và D-9-5, logic lựa chọn ngành và nhượng quyền, và quy trình di trú và khởi nghiệp thực tế. Tập này đề cập đến viễn cảnh dài hạn sau khi định cư tại Hàn Quốc.","metaDescription":"Sau khi visa D-9-4 hoặc D-9-5 được cấp, định cư mới bắt đầu — và đó là một khung thời gian dài. Gia hạn thời hạn lưu trú, chuyển đổi sang Lưu trú Dài hạn F-2-99, gia đình trên F-3, tuyển sinh đại học cho con, mua bất động sản, Đạo luật Bảo vệ Thuê Tòa nhà Thương mại, chăm sóc sức khỏe công cộng, và hỗ trợ doanh nghiệp nhỏ Hàn Quốc áp dụng cho hộ kinh doanh cá thể nước ngoài trên cùng điều khoản (2026).","series":"Episode 4 · Chuỗi Định cư Kinh doanh","publishedAt":"2026.05.01","updatedAt":"2026.05.06","readingMin":14,"sections":[{"id":"s1","heading":"Nhận được visa là nơi hành trình thực sự bắt đầu","blocks":[{"type":"p","text":"Khoảnh khắc visa D-9-4 hoặc D-9-5 được cấp, bạn nhập cảnh Hàn Quốc, và cửa hàng mở để kinh doanh là <b>không phải kết thúc của Định cư Kinh doanh, mà là bắt đầu</b>. Từ thời điểm đó, lưu trú dài hạn tại Hàn Quốc bắt đầu, và các vấn đề mới mở ra theo thứ tự: gia hạn thời hạn lưu trú, định cư gia đình, giáo dục con cái, ổn định nhà ở, quản lý tài sản, và — sau một khoảng thời gian — chuyển đổi sang visa lưu trú dài hạn. Tập này phác thảo những hệ thống pháp lý nào hoạt động ở giai đoạn này, và những gì cần được chuẩn bị trước."},{"type":"p","text":"Lawyeon Trung tâm Hỗ trợ Xuất nhập cảnh & Di trú không chỉ hỗ trợ giai đoạn di trú và khởi nghiệp ban đầu của Định cư Kinh doanh. Qua thỏa thuận hỗ trợ tiếp nối của chúng tôi, chúng tôi cung cấp tư vấn pháp lý dài hạn liên tục về <b>lưu trú, gia đình, tài sản, và tranh chấp sau khi di trú</b>. Mọi chủ đề được đề cập trong tập này đều thuộc khu vực hỗ trợ tiếp nối này."}]},{"id":"s2","heading":"Gia hạn thời hạn lưu trú D-9 — bài kiểm tra là liệu doanh nghiệp có 'sống' hay không","blocks":[{"type":"p","text":"Đối với cả D-9-4 và D-9-5, thời hạn lưu trú ban đầu thường là một năm, và bạn phải xin gia hạn trước khi hết hạn để tiếp tục lưu trú tại Hàn Quốc. Đơn gia hạn <b>có thể được nộp bắt đầu bốn tháng trước khi hết hạn</b>, và an toàn nhất là hoàn thành nộp không muộn hơn hai tháng trước khi hết hạn."},{"type":"p","text":"Điều mà Cục quản lý xuất nhập cảnh kiểm tra ở xét duyệt gia hạn rút gọn về một điều: <b>liệu doanh nghiệp có thực sự đang hoạt động hay không</b>. Cụ thể, bốn mục được đánh giá:"},{"type":"table","title":"Bốn mục được xem xét ở gia hạn D-9","headers":["Mục","Tài liệu hỗ trợ"],"rows":[["Hiệu suất doanh thu","Giấy chứng nhận nộp thuế"],["Duy trì cơ sở kinh doanh","Hợp đồng thuê thương mại, tài liệu xác minh hoạt động cửa hàng thực tế"],["Duy trì nơi cư trú","Hợp đồng thuê nhà, xác nhận cung cấp chỗ ở, hoặc bằng chứng cư trú khác"],["Tình trạng tuyển dụng","Tài liệu liên quan đến tuyển dụng"]]},{"type":"p","text":"Khi tất cả các yếu tố này tích lũy ổn định, gia hạn tiến hành thuận lợi. Bản thân gia hạn là nhiệm vụ cốt lõi của hỗ trợ tiếp nối. Từ giai đoạn định cư sớm nhất, văn phòng luật của chúng tôi thiết kế hệ thống lưu trữ hồ sơ cho bằng chứng doanh thu, hồ sơ nộp thuế, và tài liệu hoạt động kinh doanh cùng khách hàng; khi ngày gia hạn đến gần, chúng tôi chuẩn bị và nộp tài liệu đơn và xử lý mọi yêu cầu từ Cục quản lý xuất nhập cảnh."}]},{"id":"s3","heading":"Chuyển sang visa Lưu trú Dài hạn F-2-99","blocks":[{"type":"p","text":"Sau khi duy trì lưu trú D-9 năm năm trở lên, lộ trình đến <b>visa Lưu trú Dài hạn F-2-99</b> mở ra. Đó là thủ tục thay đổi tư cách lưu trú sang lưu trú dài hạn trong khi tiếp tục cùng doanh nghiệp."},{"type":"p","text":"Điều được đánh giá ở xét duyệt chuyển đổi F-2-99 khác với xét duyệt gia hạn D-9. Gia hạn D-9 hỏi 'doanh nghiệp có sống không?' Chuyển đổi F-2-99 hỏi <b>liệu người nộp đơn đã ổn định hòa nhập vào xã hội Hàn Quốc hay chưa</b>. Cụ thể, bốn lĩnh vực được đánh giá:"},{"type":"table","title":"Xét duyệt Chuyển đổi F-2-99 · Bốn lĩnh vực đánh giá","headers":["Lĩnh vực","Nội dung"],"rows":[["Cư trú","Liệu một nơi cư trú phù hợp cho lưu trú dài hạn đã được đảm bảo"],["Hạnh kiểm tốt","Liệu vi phạm Luật Quản lý Xuất nhập cảnh, hình phạt hình sự thông thường, hoặc nợ thuế có vượt quá ngưỡng nhất định"],["Thu nhập & tài sản","Tài sản từ 20.000.000 KRW trở lên; thu nhập kinh doanh hàng năm từ 40.000.000 KRW trở lên"],["Khả năng tiếng Hàn & hiểu biết văn hóa","KIIP cấp 4 trở lên, hoặc tốt nghiệp đại học Hàn Quốc"]],"note":"Tiêu chuẩn đánh giá cụ thể có thể thay đổi; cần xác minh lại tại thời điểm nộp đơn."},{"type":"callout","text":"Điểm quan trọng là <b>thiết kế cuộc sống trong thời gian lưu trú D-9 sao cho các lĩnh vực này tự nhiên tích lũy</b>. Đây không phải là điều có thể đột ngột chuẩn bị năm năm sau."},{"type":"p","text":"Một lưu ý về thuật ngữ: F-2-99 chưa phải là quyền thường trú theo nghĩa nghiêm ngặt. Nó là tư cách lưu trú dài hạn mở ra lộ trình đến <b>F-5 (Quyền Thường trú)</b>, thường được xem xét sau vài năm bổ sung trên F-2-99 với thu nhập ổn định, hạnh kiểm tốt, và hoạt động kinh doanh liên tục. Đối với chủ doanh nghiệp nước ngoài, F-2-99 đánh dấu sự chuyển đổi từ lưu trú 'điều kiện theo doanh nghiệp' dưới D-9 — nơi visa đứng hoặc rơi với hiệu suất doanh nghiệp — sang lưu trú 'theo giai đoạn cuộc sống', nơi cơ sở để ở lại Hàn Quốc đã chuyển từ một doanh nghiệp đơn lẻ sang cuộc sống tổng thể của người nộp đơn tại Hàn Quốc. F-5 theo sau giai đoạn này như cột mốc tiếp theo cho những người dự định ở lại vô thời hạn."}]},{"id":"s4","heading":"Định cư gia đình — những gì diễn ra trên tư cách F-3","blocks":[{"type":"p","text":"Như đã đề cập trong Tập 2 và 3, khi người sở hữu D-9 mời vợ/chồng và con vị thành niên đến Hàn Quốc, gia đình nhận <b>tư cách F-3 (Thân nhân đi cùng)</b>. Ba tình huống thường gặp nhất trong vận hành F-3 thực tế như sau."},{"type":"numbered","label":"VẤN ĐỀ","items":[{"n":1,"title":"Hạn chế việc làm cho vợ/chồng","text":"Tư cách F-3 bị hạn chế làm việc theo nguyên tắc chung. Nếu vợ/chồng muốn làm việc tại Hàn Quốc, một thay đổi sang tư cách lưu trú riêng phải được xem xét. Tùy thuộc vào nền tảng giáo dục và sự nghiệp của vợ/chồng, chuyển đổi sang E-7 (Hoạt động đặc biệt) hoặc tương tự có thể khả thi. Nếu vợ/chồng muốn khởi nghiệp riêng, cũng có lộ trình đáp ứng yêu cầu D-9-4 và chuyển sang tư cách hộ kinh doanh cá thể độc lập. Bất kỳ lộ trình nào đều yêu cầu các điều kiện đủ tiêu chuẩn cụ thể và chuẩn bị tài liệu, nên xem xét trước là cần thiết."},{"n":2,"title":"Đăng ký học cho con","text":"Trẻ em trong tuổi đi học có thể đăng ký vào các trường tiểu học, trung học cơ sở, và trung học phổ thông công lập hoặc tư thục Hàn Quốc. Nguyên tắc là phân bổ qua Sở Giáo dục có thẩm quyền cho nơi cư trú, và các chương trình chuẩn bị tiếng Hàn cho học sinh nước ngoài được cung cấp riêng tại các trường công. Trường tư tuân theo tiêu chuẩn nhập học chuyển trường riêng của từng trường."},{"n":3,"title":"Liên kết thời hạn lưu trú","text":"Thời hạn lưu trú F-3 được liên kết với thời hạn lưu trú của người sở hữu chính (người sở hữu D-9). Khi người sở hữu chính được gia hạn, F-3 được gia hạn cùng; khi người sở hữu chính chuyển sang F-2-99, lưu trú F-3 của gia đình được liên kết với sự ổn định của chuyển đổi đó."}]}]},{"id":"s-cta-mid","type":"midCta","blocks":[]},{"id":"s6","heading":"Người nước ngoài mua bất động sản Hàn Quốc — khung pháp lý gần như không hạn chế","blocks":[{"type":"p","text":"Người nước ngoài mua bất động sản tại Hàn Quốc phải đối mặt <b>với gần như không có hạn chế pháp lý hoặc quy định nào</b>. Khung thuế cơ bản tương tự như áp dụng cho công dân Hàn Quốc. Thuế mua khi mua, thuế tài sản và Thuế Sở hữu Bất động sản Tổng hợp trong thời gian sở hữu, và thuế thu nhập từ chuyển nhượng khi bán đều được áp đặt theo cùng cấu trúc với người Hàn. Không có phụ phí riêng nào dựa trên quốc tịch; tuy nhiên, các điều khoản đặc biệt yêu cầu cư trú là điều kiện — chẳng hạn miễn thuế một-hộ-một-nhà — có thể áp dụng khác nhau tùy thuộc hình thức tư cách lưu trú đang giữ."},{"type":"p","text":"Khi mua bất động sản nhà ở, cấu trúc <b>tài chính thế chấp</b> không khác biệt đáng kể so với cấu trúc có sẵn cho người Hàn. Tuy nhiên, ngoài giá trị thế chấp, tài liệu thu nhập và tài sản dựa trên Hàn Quốc trở thành tài liệu xét duyệt trung tâm, nên việc gia hạn được ưu tiên khi đăng ký kinh doanh đã được theo sau bởi sự tích lũy ổn định doanh thu và khai thuế. Văn phòng luật của chúng tôi bao gồm phân tích tiêu đề bất động sản mục tiêu, xem xét hợp đồng, và phân tích thuế liên quan trong <b>phạm vi tư vấn toàn diện</b> của chúng tôi."}]},{"id":"s7","heading":"Đạo luật Bảo vệ Thuê Tòa nhà Thương mại bảo vệ chủ cửa hàng nước ngoài như thế nào","blocks":[{"type":"p","text":"Khi vận hành kinh doanh với tư cách người thuê thương mại, <b>Đạo luật Bảo vệ Thuê Tòa nhà Thương mại</b> của Hàn Quốc cung cấp cho chủ cửa hàng hai cơ chế bảo vệ quan trọng: <b>quyền yêu cầu gia hạn hợp đồng</b> và <b>bảo vệ cơ hội thu hồi tiền chuyển nhượng (권리금)</b>."},{"type":"callout","text":"Hai cơ chế bảo vệ này <b>áp dụng cho chủ cửa hàng nước ngoài trên cùng điều khoản như chủ cửa hàng Hàn Quốc</b>. Đạo luật Bảo vệ Thuê Tòa nhà Thương mại không phân biệt áp dụng dựa trên quốc tịch của người thuê. Tuy nhiên, một số điều khoản áp dụng có giới hạn trong trường hợp không gian thương mại lớn nơi tiền đặt cọc quy đổi vượt quá ngưỡng theo luật, nên cần xác minh tính áp dụng tại giai đoạn ký hợp đồng."}]},{"id":"s8","heading":"Bảo hiểm xã hội — cùng khung cơ bản như đối với công dân Hàn Quốc","blocks":[{"type":"p","text":"Trong hệ thống bảo hiểm xã hội của Hàn Quốc, Bảo hiểm Y tế Quốc gia áp dụng cho người nước ngoài trên <b>cùng khung cơ bản như đối với công dân Hàn Quốc</b>, với áp dụng tự động. Với tư cách người vận hành doanh nghiệp, bạn nộp phí bảo hiểm với tư cách thuê bao khu vực, và khi tuyển nhân viên, bạn chuyển sang đăng ký dựa trên nơi làm việc. Sau <b>sáu tháng trở lên cư trú</b> tại Hàn Quốc, đăng ký khu vực áp dụng tự động. Điều tương tự áp dụng cho thành viên gia đình cư trú với tư cách F-3 thân nhân đi cùng."},{"type":"p","text":"Người vận hành doanh nghiệp nước ngoài có quyền tiếp cận chăm sóc sức khỏe công cộng thường nằm ngoài tầm với tại quê nhà. Qua đăng ký bảo hiểm y tế, gánh nặng chi phí y tế cho bản thân và gia đình được giảm một cách hệ thống — một yếu tố ổn định cuộc sống hỗ trợ vận hành kinh doanh dài hạn."}]},{"id":"s9","heading":"Hỗ trợ doanh nghiệp nhỏ Hàn Quốc áp dụng cho hộ kinh doanh cá thể nước ngoài trên cùng điều khoản","blocks":[{"type":"p","text":"Ngoài các bảo vệ pháp lý của luật bất động sản và thuê, và khung bảo hiểm xã hội, chủ doanh nghiệp nước ngoài định cư tại Hàn Quốc còn có quyền tiếp cận một loại tài nguyên công cộng nữa thường bị bỏ qua: <b>hệ sinh thái hỗ trợ doanh nghiệp nhỏ Hàn Quốc</b>."},{"type":"p","text":"Chính phủ Hàn Quốc vận hành một loạt chương trình cho chủ doanh nghiệp nhỏ, bao gồm các khoản vay chính sách lãi suất thấp, tài chính được bảo lãnh, trợ cấp ổn định kinh doanh, và quỹ hỗ trợ khẩn cấp. Các chương trình này được quản lý bởi <b>Cơ quan Thúc đẩy Thị trường Doanh nghiệp Nhỏ Hàn Quốc (SEMAS)</b>, theo Đạo luật Khung về Doanh nghiệp Nhỏ. <b>Quốc tịch không phải là yếu tố phân biệt: bất kỳ hộ kinh doanh cá thể nào đáp ứng tiêu chuẩn doanh nghiệp nhỏ theo luật — chẳng hạn ngưỡng số lượng nhân viên — đều đủ điều kiện trên cùng điều khoản, dù là người Hàn hay người nước ngoài.</b> Một người nước ngoài đã hoàn thành đăng ký kinh doanh hộ cá thể trở nên đủ điều kiện cho cùng hỗ trợ, trên cùng điều kiện, như chủ doanh nghiệp nhỏ Hàn Quốc."},{"type":"callout","text":"Bản thân khung pháp lý không tách biệt hộ kinh doanh cá thể nước ngoài và trong nước — cả hai đều được bao gồm trong cùng danh mục 'doanh nghiệp nhỏ'. Trong thực tế, điều này có nghĩa là một người vận hành nước ngoài đã định cư có quyền tiếp cận các tài nguyên công cộng thường không có sẵn cho họ tại quê nhà: tài chính lãi suất thấp cho vốn lưu động, bảo lãnh do chính phủ hậu thuẫn, hỗ trợ trong giai đoạn suy giảm kinh doanh. Các chương trình này có sẵn không chỉ tại thời điểm khai trương mà trong suốt vòng đời của doanh nghiệp — bao gồm giai đoạn được đề cập trong tập này, khi tư cách lưu trú của bạn chuyển từ D-9 sang F-2-99 và xa hơn."}]},{"id":"s10","heading":"Các lĩnh vực được bao phủ bởi thỏa thuận hỗ trợ tiếp nối","blocks":[{"type":"p","text":"Tất cả các chủ đề được bao phủ ở trên đều thuộc phạm vi <b>thỏa thuận hỗ trợ tiếp nối</b> của văn phòng luật chúng tôi."},{"type":"numbered","label":"PHẠM VI","items":[{"n":1,"title":"Quản lý tư cách lưu trú","text":"Gia hạn thời hạn lưu trú D-9, chuyển đổi sang visa Lưu trú Dài hạn F-2-99"},{"n":2,"title":"Quản lý lưu trú gia đình","text":"Gia hạn F-3, thay đổi tư cách của vợ/chồng, các vấn đề lưu trú liên quan đến giáo dục con cái"},{"n":3,"title":"Giải quyết tranh chấp","text":"Tranh chấp hợp đồng với tổng công ty nhượng quyền, tranh chấp thuê thương mại với chủ nhà, tranh chấp hợp đồng lao động với nhân viên"},{"n":4,"title":"Xem xét hợp đồng","text":"Gia hạn và chấm dứt hợp đồng nhượng quyền, gia hạn thuê thương mại và thu hồi tiền chuyển nhượng, thực hiện hợp đồng lao động"},{"n":5,"title":"Tư vấn bất động sản","text":"Phân tích tiêu đề và nghĩa vụ báo cáo cho việc mua và bán bất động sản nhà ở và thương mại"},{"n":6,"title":"Tư vấn thuế","text":"Xem xét các vấn đề thuế hộ kinh doanh cá thể, phân tích thuế bất động sản"}]},{"type":"p","text":"Thỏa thuận hỗ trợ tiếp nối không phải là điều mọi khách hàng phải ký. Nó có thể được lựa chọn trong phạm vi cần thiết và tại thời điểm cần thiết, và tư vấn cho các vấn đề cụ thể từng phiên cũng có sẵn."}]},{"id":"closing","heading":"Định cư là một sự nghiệp dài hạn","blocks":[{"type":"p","text":"Nếu Tập 1 đến 3 đề cập đến <b>khởi đầu của Định cư Kinh doanh tại Hàn Quốc</b>, thì Tập 4 đã đề cập đến <b>khởi đầu của định cư</b>. Quan điểm cốt lõi mà tập này truyền tải là việc nhận visa không phải là điểm đến của dự án — đó là điểm khởi đầu của một khung thời gian dài. Gia hạn lưu trú chu kỳ hai năm. Chuyển đổi năm năm sang F-2-99, và cột mốc tiếp theo của F-5 Quyền Thường trú theo sau. Vòng cung mười năm về sự ổn định thuê thương mại. Các bảo vệ pháp lý của Đạo luật Bảo vệ Thuê Tòa nhà Thương mại và hệ thống chăm sóc sức khỏe công cộng. Các chương trình hỗ trợ doanh nghiệp nhỏ áp dụng cho hộ kinh doanh cá thể nước ngoài trên cùng điều khoản như cho công dân Hàn Quốc. Và xuyên suốt, định cư gia đình và hình thành tài sản tiếp tục giữa các giai đoạn."},{"type":"p","text":"Trên bốn tập của loạt này, chúng ta đã bao phủ: vì sao D-9-4 và D-9-5 là loại visa phù hợp với Định cư Kinh doanh hộ cá thể nước ngoài tại Hàn Quốc (Tập 1); cách lựa chọn ngành và vì sao nhượng quyền cung cấp lộ trình có thể dự đoán nhất (Tập 2); quy trình năm giai đoạn từ tư vấn sơ bộ qua hỗ trợ tiếp nối (Tập 3); và viễn cảnh dài hạn bắt đầu sau khi visa được cấp (tập này). Định cư Kinh doanh tại Hàn Quốc hiếm khi là một sự kiện đơn lẻ — đó là một chuỗi các quyết định tích lũy qua nhiều năm. Thiết kế các quyết định đó từ sớm, cùng nhau, là điều chúng tôi làm."},{"type":"p","text":"Lawyeon Trung tâm Hỗ trợ Xuất nhập cảnh & Di trú quy tụ các luật sư giàu kinh nghiệm từ Văn phòng Luật Lawyeon, điều phối viên-phiên dịch, và chuyên gia di trú khởi nghiệp để hỗ trợ Định cư Kinh doanh hộ cá thể của người nước ngoài qua D-9-4 và D-9-5. Tư vấn ban đầu miễn phí, và người nộp đơn có thể gửi yêu cầu trực tiếp từ quê nhà qua luồng tư vấn của chúng tôi."}]}],"related":[{"tag":"EP 1","title":"Cách bắt đầu kinh doanh tại Hàn Quốc cho người nước ngoài — Hướng dẫn toàn diện về visa D-9-4, D-9-5 cho hộ kinh doanh cá thể (2026)","url":"cach-bat-dau-kinh-doanh-tai-han-quoc-cho-nguoi-nuoc-ngoai-2026"},{"tag":"EP 2","title":"Người nước ngoài nên mở loại nhượng quyền nào tại Hàn Quốc? Ngành, thương hiệu & Tài liệu công khai (2026)","url":"kinh-doanh-nhuong-quyen-tai-han-quoc-cho-nguoi-nuoc-ngoai-2026"},{"tag":"EP 3","title":"Cách mở cửa hàng tại Hàn Quốc cho người nước ngoài — Quy trình từng bước 2026 từ tư vấn sơ bộ đến ngày khai trương","url":"quy-trinh-mo-cua-hang-tai-han-quoc-cho-nguoi-nuoc-ngoai-2026"}]}$vi$::jsonb,
    NOW(),
